using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Data.Entity;
using System.Linq;
using System.Text.RegularExpressions;
using System.Threading.Tasks;
using System.Web;
using System.Web.Mvc;

namespace MyStore.Web.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        [HttpGet]
        public async Task<ActionResult> Details(int id)
        {
            var product = await _db.Products.SingleOrDefaultAsync(p => p.Id == id);
            if (product == null) return HttpNotFound();

            var reviews = await _db.Reviews
                .Where(r => r.ProductId == id && r.IsApproved)
                .OrderByDescending(r => r.CreatedUtc)
                .Select(r => new ReviewViewModel
                {
                    Id = r.Id,
                    ProductId = r.ProductId,
                    UserDisplayName = r.UserDisplayName,
                    Rating = r.Rating,
                    CreatedUtc = r.CreatedUtc,
                    BodyHtml = ReviewFormatting.ToSafeBasicHtml(r.Body)
                })
                .ToListAsync();

            var vm = new ProductDetailsViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Description = product.Description,
                Reviews = reviews
            };

            return View(vm);
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing) _db.Dispose();
            base.Dispose(disposing);
        }
    }

    public static class ReviewFormatting
    {
        private static readonly Regex BoldRegex = new Regex(@"\*\*(.+?)\*\*", RegexOptions.Compiled | RegexOptions.Singleline);
        private static readonly Regex ItalicRegex = new Regex(@"\*(.+?)\*", RegexOptions.Compiled | RegexOptions.Singleline);

        public static string ToSafeBasicHtml(string input)
        {
            input = input ?? string.Empty;

            var encoded = HttpUtility.HtmlEncode(input);

            encoded = encoded.Replace("\r\n", "\n").Replace("\r", "\n");
            encoded = encoded.Replace("\n", "<br />");

            encoded = BoldRegex.Replace(encoded, "<strong>$1</strong>");
            encoded = ItalicRegex.Replace(encoded, "<em>$1</em>");

            return encoded;
        }
    }

