/* Views/Product/Details.cshtml */
@model MyStore.Web.Controllers.ProductDetailsViewModel
@{
    ViewBag.Title = Model.ProductName;
}

<h2>@Model.ProductName</h2>

@if (!String.IsNullOrWhiteSpace(Model.Description))
{
    <p>@Model.Description</p>
}

<h3>Reviews (@Model.Reviews.Count)</h3>

@if (Model.Reviews == null || !Model.Reviews.Any())
{
    <p>No reviews yet.</p>
}
else
{
    <ul class="reviews">
        @foreach (var r in Model.Reviews)
        {
            <li class="review">
                <div class="review-meta">
                    <strong>@r.UserDisplayName</strong>
                    <span> - @r.CreatedUtc.ToLocalTime().ToString("yyyy-MM-dd HH:mm")</span>
                    <span> - Rating: @r.Rating/5</span>
                </div>
                <div class="review-body">
                    @Html.Raw(r.BodyHtml)
                </div>
            </li>
        }
    </ul>
}